import React, { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../App';
import api from '../api';

const I = ({ c, style }) => <i className={`fa-solid ${c}`} style={style} />;

const ADMIN_TABS = [
  { key:'overview',      icon:'fa-chart-line',  label:'Overview'      },
  { key:'users',         icon:'fa-users',        label:'Users'         },
  { key:'hospitals',     icon:'fa-hospital',     label:'Hospitals'     },
  { key:'knowledge',     icon:'fa-brain',        label:'AI Knowledge'  },
];

const ROLES         = ['USER','ADMIN'];
const BLOOD_GROUPS  = ['A+','A-','B+','B-','AB+','AB-','O+','O-'];
const HOSPITAL_TYPES = ['government','private','mission','clinic'];
const SEVERITIES    = ['Mild','Mild-Moderate','Moderate','Moderate-Severe','Severe'];
const FA_ICONS      = [
  'fa-droplet','fa-eye','fa-sun','fa-brain','fa-seedling','fa-shield-halved',
  'fa-shield','fa-bone','fa-lemon','fa-dumbbell','fa-heart','fa-lungs',
  'fa-circle-dot','fa-stethoscope','fa-pills','fa-flask',
];
const COLORS = [
  '#dc2626','#d97706','#f59e0b','#0891b2','#16a34a','#7c3aed',
  '#0f766e','#64748b','#ea580c','#b45309','#db2777','#0284c7',
];

// ── Reusable Modal ────────────────────────────────────────────────────────────
function Modal({ title, onClose, children, wide }) {
  return (
    <div style={{ position:'fixed',inset:0,background:'rgba(0,0,0,0.5)',zIndex:1000,
                  display:'flex',alignItems:'flex-end',justifyContent:'center',
                  padding:'0' }}
         onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div className="modal-inner" style={{
        background:'#fff', borderRadius:'16px 16px 0 0', width:'100%',
        maxWidth: wide ? 680 : 520, maxHeight:'90vh', overflow:'auto',
        boxShadow:'0 -4px 40px rgba(0,0,0,0.2)',
      }}>
        <div style={{ padding:'1rem 1.25rem', borderBottom:'1px solid #e5e7eb',
                      display:'flex',alignItems:'center',justifyContent:'space-between',
                      position:'sticky',top:0,background:'#fff',zIndex:1 }}>
          <h3 style={{ fontSize:'1rem',fontWeight:700,fontFamily:'Outfit,sans-serif' }}>{title}</h3>
          <button onClick={onClose} style={{ background:'none',border:'none',cursor:'pointer',
                                             color:'#6b7280',fontSize:'1.1rem',width:30,height:30,
                                             borderRadius:6,display:'flex',alignItems:'center',justifyContent:'center' }}>
            <I c="fa-xmark"/>
          </button>
        </div>
        <div style={{ padding:'1.25rem' }}>{children}</div>
      </div>
    </div>
  );
}

// ── Confirm dialog ────────────────────────────────────────────────────────────
function Confirm({ msg, onConfirm, onCancel }) {
  return (
    <Modal title="Confirm" onClose={onCancel}>
      <div style={{ textAlign:'center' }}>
        <I c="fa-triangle-exclamation" style={{ fontSize:'2rem',color:'#dc2626',marginBottom:12,display:'block' }}/>
        <p style={{ fontSize:'0.875rem',color:'#374151',marginBottom:16 }}>{msg}</p>
        <div style={{ display:'flex',gap:8,justifyContent:'center' }}>
          <button className="btn btn-ghost" onClick={onCancel}>Cancel</button>
          <button className="btn btn-danger" onClick={onConfirm}>
            <I c="fa-trash" style={{marginRight:6}}/>Delete
          </button>
        </div>
      </div>
    </Modal>
  );
}

// ── Form helpers ──────────────────────────────────────────────────────────────
function FormField({ label, children, hint }) {
  return (
    <div className="form-group">
      <label className="form-label">{label}</label>
      {children}
      {hint && <div style={{ fontSize:'0.7rem',color:'#9ca3af',marginTop:3 }}>{hint}</div>}
    </div>
  );
}

// ── Overview ──────────────────────────────────────────────────────────────────
function Overview() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState('');

  const load = useCallback(() => {
    setLoading(true); setErr('');
    api.get('/api/admin/stats')
      .then(r => { setStats(r.data); setLoading(false); })
      .catch(e => { setErr(`Failed to load stats: ${e.response?.data?.error||e.message}`); setLoading(false); });
  },[]);
  useEffect(()=>{ load(); },[load]);

  if (loading) return <div style={{textAlign:'center',padding:'3rem'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div>;
  if (err) return <div className="alert alert-error">{err} <button className="btn btn-ghost btn-sm" onClick={load} style={{marginLeft:8}}>Retry</button></div>;

  const CARDS = [
    { label:'Registered Users',  value:stats.users,         color:'#16a34a', icon:'fa-users'       },
    { label:'AI Analyses Run',   value:stats.analyses,      color:'#0891b2', icon:'fa-stethoscope'  },
    { label:'Hospitals Listed',  value:stats.hospitals,     color:'#d97706', icon:'fa-hospital'     },
    { label:'Active Deficiencies',value:stats.deficiencies, color:'#7c3aed', icon:'fa-brain'        },
  ];

  return (
    <div style={{ display:'flex',flexDirection:'column',gap:'1rem' }}>
      <div style={{ display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(160px,1fr))',gap:12 }}>
        {CARDS.map(c => (
          <div key={c.label} className="card" style={{ textAlign:'center',border:`1px solid ${c.color}20`,padding:'1.25rem' }}>
            <I c={c.icon} style={{ fontSize:'1.5rem',color:c.color,marginBottom:8,display:'block' }}/>
            <div style={{ fontSize:'2rem',fontWeight:800,fontFamily:'Fraunces,serif',color:c.color,lineHeight:1 }}>{c.value}</div>
            <div style={{ fontSize:'0.75rem',color:'#6b7280',fontWeight:600,marginTop:4 }}>{c.label}</div>
          </div>
        ))}
      </div>

      <div className="card">
        <div style={{ display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1rem',flexWrap:'wrap',gap:8 }}>
          <h4 style={{ fontFamily:'Outfit,sans-serif',fontWeight:700,fontSize:'0.95rem' }}>
            <I c="fa-clock-rotate-left" style={{ marginRight:8,color:'#16a34a' }}/>Recent User Analyses
          </h4>
          <button onClick={load} className="btn btn-ghost btn-sm"><I c="fa-rotate" style={{marginRight:4}}/>Refresh</button>
        </div>
        {stats.recent?.length ? stats.recent.map(r => (
          <div key={r.id} style={{ padding:'10px 12px',background:'#f9fafb',borderRadius:8,border:'1px solid #f1f1f1',marginBottom:8 }}>
            <div style={{ display:'flex',justifyContent:'space-between',marginBottom:4,flexWrap:'wrap',gap:4 }}>
              <span style={{ fontSize:'0.8rem',fontWeight:600,color:'#374151' }}>
                <I c="fa-user" style={{ marginRight:5,color:'#9ca3af' }}/>{r.user_name}
                <span style={{ color:'#9ca3af',fontWeight:400,marginLeft:4 }}>({r.email})</span>
              </span>
              <span style={{ fontSize:'0.72rem',color:'#9ca3af' }}>{new Date(r.timestamp).toLocaleString('en-KE')}</span>
            </div>
            <div style={{ fontSize:'0.82rem',color:'#374151',fontStyle:'italic',marginBottom:6 }}>
              "{r.symptoms.substring(0,90)}{r.symptoms.length>90?'...':''}"
            </div>
            <div style={{ display:'flex',flexWrap:'wrap',gap:4 }}>
              {(r.results||[]).slice(0,3).map(res => (
                <span key={res.id} style={{ background:`${res.color}12`,color:res.color,border:`1px solid ${res.color}30`,borderRadius:12,padding:'1px 8px',fontSize:'0.7rem',fontWeight:700 }}>
                  {res.name} · {res.confidence}%
                </span>
              ))}
            </div>
          </div>
        )) : <p style={{ color:'#6b7280',fontSize:'0.875rem' }}>No analyses yet.</p>}
      </div>

      <SystemStatus/>
    </div>
  );
}

function SystemStatus() {
  const [health, setHealth] = useState(null);
  useEffect(()=>{
    api.get('/api/health').then(r=>setHealth({ok:true,...r.data})).catch(()=>setHealth({ok:false}));
  },[]);
  const rows = health ? [
    { label:'Flask API',           ok:health.ok,  status:health.ok?'Online':'Offline' },
    { label:'SQLite Database',     ok:health.ok,  status:health.ok?`Connected (${health.registered_users} users)`:'Disconnected' },
    { label:'AI Knowledge Base',   ok:health.ok,  status:health.ok?`${health.active_deficiencies} active deficiencies`:'Unknown' },
    { label:'JS Symptom Engine',   ok:true,        status:'Active (runs in browser)' },
    { label:'OpenStreetMap',       ok:true,        status:'Free — no API key needed' },
    { label:'JWT Auth',            ok:true,        status:'Enabled (12h token expiry)' },
  ] : [];
  return (
    <div className="card">
      <h4 style={{ fontFamily:'Outfit,sans-serif',fontWeight:700,fontSize:'0.95rem',marginBottom:'1rem' }}>
        <I c="fa-server" style={{ marginRight:8,color:'#16a34a' }}/>System Status
      </h4>
      {!health ? <div style={{textAlign:'center'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div> :
        rows.map(r=>(
          <div key={r.label} style={{ display:'flex',justifyContent:'space-between',alignItems:'center',padding:'9px 0',borderBottom:'1px solid #f3f4f6' }}>
            <span style={{ fontSize:'0.875rem',color:'#374151' }}>{r.label}</span>
            <span style={{ fontSize:'0.78rem',fontWeight:700,color:r.ok?'#16a34a':'#dc2626',display:'flex',alignItems:'center',gap:5 }}>
              <I c={r.ok?'fa-circle-check':'fa-circle-xmark'}/>{r.status}
            </span>
          </div>
        ))
      }
    </div>
  );
}

// ── Users ─────────────────────────────────────────────────────────────────────
function Users() {
  const [users, setUsers]         = useState([]);
  const [loading, setLoading]     = useState(true);
  const [search, setSearch]       = useState('');
  const [editUser, setEditUser]   = useState(null);
  const [detailUser, setDetailUser] = useState(null);
  const [saving, setSaving]       = useState(false);
  const [msg, setMsg]             = useState('');
  const [confirm, setConfirm]     = useState(null);

  const load = useCallback(()=>{
    setLoading(true);
    api.get(`/api/admin/users${search?`?q=${encodeURIComponent(search)}`:''}`)
      .then(r=>{ setUsers(r.data); setLoading(false); })
      .catch(()=>setLoading(false));
  },[search]);
  useEffect(()=>{ load(); },[load]);

  const openDetail = async uid => {
    try { const r = await api.get(`/api/admin/users/${uid}`); setDetailUser(r.data); } catch {}
  };

  const save = async form => {
    setSaving(true); setMsg('');
    try { await api.put(`/api/admin/users/${form.id}`,form); setMsg('Updated!'); setEditUser(null); load(); }
    catch(e){ setMsg(e.response?.data?.error||'Save failed'); }
    setSaving(false);
  };

  const del = async uid => {
    try { await api.delete(`/api/admin/users/${uid}`); setConfirm(null); load(); }
    catch(e){ alert(e.response?.data?.error||'Delete failed'); }
  };

  return (
    <div>
      <div style={{ display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1rem',gap:8,flexWrap:'wrap' }}>
        <h4 style={{ fontFamily:'Outfit,sans-serif',fontWeight:700,fontSize:'0.95rem' }}>
          <I c="fa-users" style={{ marginRight:8,color:'#16a34a' }}/>{users.length} Users
        </h4>
        <div style={{ display:'flex',gap:8,flexWrap:'wrap' }}>
          <div style={{ position:'relative' }}>
            <I c="fa-magnifying-glass" style={{ position:'absolute',left:10,top:'50%',transform:'translateY(-50%)',color:'#9ca3af',fontSize:'0.8rem' }}/>
            <input className="form-input" value={search} onChange={e=>setSearch(e.target.value)}
                   placeholder="Search users..." style={{ paddingLeft:30,width:200 }}/>
          </div>
          <button onClick={load} className="btn btn-ghost btn-sm"><I c="fa-rotate" style={{marginRight:4}}/>Refresh</button>
        </div>
      </div>

      {msg && <div className="alert alert-success" style={{marginBottom:'1rem'}}>{msg}</div>}

      {loading ? <div style={{textAlign:'center',padding:'2rem'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div> : (
        <div style={{ background:'#fff',borderRadius:12,border:'1px solid #e5e7eb',overflow:'hidden' }}>
          <table style={{ width:'100%',borderCollapse:'collapse' }}>
            <thead style={{ background:'#f9fafb' }}>
              <tr>{['User','Role','Analyses','Last Active','Actions'].map(h=>(
                <th key={h} style={{ padding:'10px 14px',textAlign:'left',fontSize:'0.7rem',fontWeight:700,color:'#6b7280',textTransform:'uppercase',letterSpacing:'0.05em',borderBottom:'1px solid #e5e7eb' }}>{h}</th>
              ))}</tr>
            </thead>
            <tbody>
              {users.map((u,i)=>(
                <tr key={u.id} style={{ background:i%2?'#fafafa':'white' }}
                    onMouseEnter={e=>e.currentTarget.style.background='#f0fdf4'}
                    onMouseLeave={e=>e.currentTarget.style.background=i%2?'#fafafa':'white'}>
                  <td style={{ padding:'10px 14px',borderBottom:'1px solid #f1f1f1' }}>
                    <div style={{ display:'flex',alignItems:'center',gap:8 }}>
                      <div style={{ width:28,height:28,borderRadius:'50%',background:u.role==='ADMIN'?'linear-gradient(135deg,#dc2626,#b91c1c)':'linear-gradient(135deg,#16a34a,#15803d)',display:'flex',alignItems:'center',justifyContent:'center',color:'white',fontSize:'0.75rem',fontWeight:700,flexShrink:0 }}>
                        {(u.name||'U')[0].toUpperCase()}
                      </div>
                      <div>
                        <div style={{ fontSize:'0.875rem',fontWeight:600 }}>{u.name}</div>
                        <div style={{ fontSize:'0.72rem',color:'#9ca3af' }}>{u.email}</div>
                      </div>
                    </div>
                  </td>
                  <td style={{ padding:'10px 14px',borderBottom:'1px solid #f1f1f1' }}>
                    <span style={{ background:u.role==='ADMIN'?'#fef2f2':'#f0fdf4',color:u.role==='ADMIN'?'#dc2626':'#16a34a',borderRadius:8,padding:'2px 8px',fontSize:'0.7rem',fontWeight:700 }}>{u.role}</span>
                  </td>
                  <td style={{ padding:'10px 14px',fontSize:'0.875rem',fontWeight:600,borderBottom:'1px solid #f1f1f1' }}>{u.analyses_count}</td>
                  <td style={{ padding:'10px 14px',fontSize:'0.75rem',color:'#6b7280',borderBottom:'1px solid #f1f1f1' }}>
                    {u.last_active ? new Date(u.last_active).toLocaleDateString('en-KE') : <span style={{color:'#d1d5db'}}>Never</span>}
                  </td>
                  <td style={{ padding:'10px 14px',borderBottom:'1px solid #f1f1f1' }}>
                    <div style={{ display:'flex',gap:4 }}>
                      <button onClick={()=>openDetail(u.id)} title="View" style={{ background:'#f0fdf4',border:'1px solid #bbf7d0',color:'#16a34a',borderRadius:6,padding:'4px 8px',cursor:'pointer',fontSize:'0.75rem' }}><I c="fa-eye"/></button>
                      <button onClick={()=>setEditUser({...u,password:''})} title="Edit" style={{ background:'#eff6ff',border:'1px solid #bfdbfe',color:'#1d4ed8',borderRadius:6,padding:'4px 8px',cursor:'pointer',fontSize:'0.75rem' }}><I c="fa-pen"/></button>
                      <button onClick={()=>setConfirm({id:u.id,name:u.name})} title="Delete" style={{ background:'#fef2f2',border:'1px solid #fca5a5',color:'#dc2626',borderRadius:6,padding:'4px 8px',cursor:'pointer',fontSize:'0.75rem' }}><I c="fa-trash"/></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {!users.length && <div style={{ textAlign:'center',padding:'2rem',color:'#6b7280',fontSize:'0.875rem' }}>No users found.</div>}
        </div>
      )}

      {editUser && (
        <Modal title={`Edit — ${editUser.name}`} onClose={()=>setEditUser(null)}>
          <UserForm user={editUser} saving={saving} msg={msg} onSave={save} onCancel={()=>setEditUser(null)}/>
        </Modal>
      )}
      {detailUser && (
        <Modal title="User Details" onClose={()=>setDetailUser(null)}>
          <UserDetail data={detailUser} onEdit={u=>{setDetailUser(null);setEditUser({...u,password:''});}}/>
        </Modal>
      )}
      {confirm && <Confirm msg={`Delete ${confirm.name}? This removes all their data permanently.`} onConfirm={()=>del(confirm.id)} onCancel={()=>setConfirm(null)}/>}
    </div>
  );
}

function UserForm({ user, saving, msg, onSave, onCancel }) {
  const [f, setF] = useState({...user});
  const s = k => e => setF(x=>({...x,[k]:e.target.value}));
  return (
    <div>
      {msg && <div className={`alert ${msg==='Updated!'?'alert-success':'alert-error'}`} style={{marginBottom:'1rem'}}>{msg}</div>}
      <FormField label="Full Name"><input className="form-input" value={f.name||''} onChange={s('name')} required/></FormField>
      <FormField label="Email"><input type="email" className="form-input" value={f.email||''} onChange={s('email')} required/></FormField>
      <div className="grid-2">
        <FormField label="Role">
          <select className="form-input" value={f.role||'USER'} onChange={s('role')}>
            {ROLES.map(r=><option key={r}>{r}</option>)}
          </select>
        </FormField>
        <FormField label="Age"><input type="number" className="form-input" value={f.age||''} onChange={s('age')} min="1" max="120"/></FormField>
      </div>
      <div className="grid-2">
        <FormField label="Blood Group">
          <select className="form-input" value={f.blood_group||''} onChange={s('blood_group')}>
            <option value="">Unknown</option>{BLOOD_GROUPS.map(b=><option key={b}>{b}</option>)}
          </select>
        </FormField>
        <FormField label="New Password" hint="Leave blank to keep current">
          <input type="password" className="form-input" value={f.password||''} onChange={s('password')} placeholder="••••••" minLength={6}/>
        </FormField>
      </div>
      <FormField label="Allergies"><input className="form-input" value={f.allergies||''} onChange={s('allergies')}/></FormField>
      <FormField label="Chronic Conditions"><input className="form-input" value={f.chronic_conditions||''} onChange={s('chronic_conditions')}/></FormField>
      <div style={{ display:'flex',gap:8,marginTop:'0.5rem' }}>
        <button className="btn btn-ghost" onClick={onCancel} style={{ flex:1,justifyContent:'center' }}>Cancel</button>
        <button className="btn btn-primary" onClick={()=>onSave(f)} disabled={saving} style={{ flex:2,justifyContent:'center' }}>
          {saving?'Saving...':<><I c="fa-floppy-disk" style={{marginRight:6}}/>Save</>}
        </button>
      </div>
    </div>
  );
}

function UserDetail({ data, onEdit }) {
  const { user, analyses } = data;
  return (
    <div>
      <div style={{ display:'flex',alignItems:'center',gap:12,marginBottom:'1rem',padding:'0.9rem',background:'#f9fafb',borderRadius:10,border:'1px solid #e5e7eb' }}>
        <div style={{ width:44,height:44,borderRadius:'50%',background:'linear-gradient(135deg,#16a34a,#15803d)',display:'flex',alignItems:'center',justifyContent:'center',color:'white',fontWeight:700,fontSize:'1.1rem',flexShrink:0 }}>
          {(user.name||'U')[0].toUpperCase()}
        </div>
        <div style={{ flex:1 }}>
          <div style={{ fontWeight:700 }}>{user.name}</div>
          <div style={{ fontSize:'0.8rem',color:'#6b7280' }}>{user.email}</div>
        </div>
        <button className="btn btn-outline btn-sm" onClick={()=>onEdit(user)}><I c="fa-pen" style={{marginRight:5}}/>Edit</button>
      </div>
      <p style={{ fontSize:'0.78rem',color:'#6b7280',marginBottom:'0.75rem' }}>
        <I c="fa-stethoscope" style={{marginRight:5}}/>Last {analyses.length} analyses:
      </p>
      {analyses.map(a=>(
        <div key={a.id} style={{ padding:'8px 12px',background:'#f9fafb',border:'1px solid #e5e7eb',borderRadius:8,marginBottom:8 }}>
          <div style={{ fontSize:'0.72rem',color:'#9ca3af',marginBottom:2 }}>{new Date(a.timestamp).toLocaleString('en-KE')}</div>
          <div style={{ fontSize:'0.82rem',fontStyle:'italic',color:'#374151',marginBottom:4 }}>"{a.symptoms.substring(0,80)}..."</div>
          <div style={{ display:'flex',flexWrap:'wrap',gap:4 }}>
            {(a.results||[]).map(r=>(
              <span key={r.id} style={{ background:`${r.color}12`,color:r.color,border:`1px solid ${r.color}30`,borderRadius:10,padding:'1px 7px',fontSize:'0.68rem',fontWeight:700 }}>
                {r.name} {r.confidence}%
              </span>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}

// ── Hospitals ─────────────────────────────────────────────────────────────────
const BLANK_H = { name:'',address:'',latitude:'',longitude:'',phone:'',type:'government',services:'',emergency:false };

function Hospitals() {
  const [list, setList]       = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch]   = useState('');
  const [edit, setEdit]       = useState(null);
  const [saving, setSaving]   = useState(false);
  const [msg, setMsg]         = useState('');
  const [confirm, setConfirm] = useState(null);

  const load = useCallback(()=>{
    setLoading(true);
    api.get(`/api/hospitals${search?`?q=${encodeURIComponent(search)}`:''}`)
      .then(r=>{ setList(r.data); setLoading(false); })
      .catch(()=>setLoading(false));
  },[search]);
  useEffect(()=>{ load(); },[load]);

  const save = async form => {
    setSaving(true); setMsg('');
    try {
      const payload = { ...form, emergency:!!form.emergency,
        services: typeof form.services==='string' ? form.services.split(',').map(s=>s.trim()).filter(Boolean) : form.services };
      form.id ? await api.put(`/api/hospitals/${form.id}`,payload) : await api.post('/api/hospitals',payload);
      setMsg(form.id?'Hospital updated!':'Hospital added!'); setEdit(null); load();
    } catch(e){ setMsg(e.response?.data?.error||'Save failed'); }
    setSaving(false);
  };

  const del = async id => {
    try { await api.delete(`/api/hospitals/${id}`); setConfirm(null); load(); }
    catch(e){ alert(e.response?.data?.error||'Delete failed'); }
  };

  return (
    <div>
      <div style={{ display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1rem',gap:8,flexWrap:'wrap' }}>
        <h4 style={{ fontFamily:'Outfit,sans-serif',fontWeight:700,fontSize:'0.95rem' }}>
          <I c="fa-hospital" style={{ marginRight:8,color:'#16a34a' }}/>{list.length} Hospitals
        </h4>
        <div style={{ display:'flex',gap:8,flexWrap:'wrap' }}>
