      <FormField label="Risk Groups" hint="One per line">
        <textarea className="form-input" value={form.risk_groups||''} onChange={s('risk_groups')} rows={3}
                  placeholder={"Pregnant women\nYoung children"} style={{ resize:'vertical' }}/>
