      </nav>
      <div style={{ borderTop:'1px solid rgba(255,255,255,0.08)',paddingTop:'1rem',marginTop:'1rem' }}>
        <button onClick={logout} style={{ display:'flex',alignItems:'center',gap:8,width:'100%',padding:'0.6rem 0.75rem',border:'none',borderRadius:8,cursor:'pointer',background:'transparent',color:'rgba(255,255,255,0.4)',fontFamily:'Outfit,sans-serif',fontSize:'0.82rem',transition:'all 0.15s' }}
                onMouseEnter={e=>{ e.currentTarget.style.background='rgba(220,38,38,0.15)'; e.currentTarget.style.color='#fca5a5'; }}
                onMouseLeave={e=>{ e.currentTarget.style.background='transparent'; e.currentTarget.style.color='rgba(255,255,255,0.4)'; }}>
          <I c="fa-right-from-bracket"/>Logout
        </button>
      </div>
    </>
  );

  return (
    <div style={{ display:'flex', minHeight:'calc(100vh - 60px)', position:'relative' }}>
      {/* Desktop Sidebar */}
      <div className="admin-sidebar" style={{ width:220,background:'#0f172a',display:'flex',flexDirection:'column',padding:'1.25rem 0.75rem',flexShrink:0 }}>
        {sidebarContent}
      </div>

      {/* Mobile Sidebar overlay */}
      {sidebarOpen && (
        <div style={{ position:'fixed',inset:0,background:'rgba(0,0,0,0.5)',zIndex:199 }} onClick={()=>setSidebarOpen(false)}>
          <div style={{ width:240,background:'#0f172a',height:'100%',padding:'1.25rem 0.75rem',display:'flex',flexDirection:'column' }}
               onClick={e=>e.stopPropagation()}>
            {sidebarContent}
          </div>
        </div>
      )}

      {/* Mobile menu toggle */}
      <button className="admin-toggle-btn" onClick={()=>setSidebarOpen(!sidebarOpen)}>
        <I c={sidebarOpen?'fa-xmark':'fa-bars'}/>
      </button>

      {/* Main content */}
      <div style={{ flex:1,padding:'1.25rem',overflow:'auto',background:'#f9fafb' }}>
        <div style={{ display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1.25rem',flexWrap:'wrap',gap:8 }}>
          <h2 style={{ fontSize:'1.15rem',display:'flex',alignItems:'center',gap:8 }}>
            <I c={current?.icon} style={{ color:'#16a34a' }}/>{current?.label}
          </h2>
          <span style={{ fontSize:'0.75rem',color:'#16a34a',background:'#f0fdf4',border:'1px solid #bbf7d0',borderRadius:20,padding:'4px 12px',display:'flex',alignItems:'center',gap:5 }}>
            <I c="fa-circle-check"/>Online
          </span>
        </div>
        {tab==='overview'  && <Overview/>}
        {tab==='users'     && <Users/>}
        {tab==='hospitals' && <Hospitals/>}
        {tab==='knowledge' && <Knowledge/>}
      </div>
    </div>
  );
}
